external_knowledge:
- "voting districts" refers to precinct IDs; 
- "upcoming elections" are those with an absentee ballot deadline in the future; 
- "highest overall participation" means the elections with the largest voter count; 
- "early and absentee voter numbers" correspond to the counts of early and absentee voters, respectively.

sql:
SELECT voter_id, first_name, last_name, email
FROM voters
WHERE voter_status = 'active' AND precinct_id = '0';

SELECT voter_count
FROM voter_turnout
WHERE voter_count = (SELECT MAX(voter_count) FROM voter_turnout);

SELECT first_name, last_name, street, city, state, zip
FROM voters
WHERE registration_date < '2023-11-01';

external_knowledge:
- 'helping out' refers to volunteers;
- 'places' are voting precincts;
- 'fall elections' are those held between November 1st and November 30th, 2022;
- 'more than 80% of their crowd capacity' means the voter turnout exceeded 80% of the precinct's capacity.

sql:
SELECT first_name, last_name
FROM voters
WHERE voter_status = 'active';

SELECT precinct_name, location 
FROM precincts
WHERE precinct_id = '1';

external_knowledge:
- 'Gardens' metaphorically represent 'precincts';
- 'Blooming with over a hundred active pollinators' refers to having 100 or more active voters;
- 'Gardeners nurturing these vibrant communities' are the election officials in charge of the precincts.

- 'initial election event' refers to the election with `election_id` = 0;
- 'people involved' includes voter ID, first name, and last name;
- 'place' includes the precinct name and location;
- 'overall turnout situation' includes the number of voters who turned out and the turnout percentage;
- 'type and amount of materials' refers to the resource type and quantity available at each voting location.

sql:
SELECT voters.voter_id, voters.first_name, voters.last_name, voters.precinct_id, precincts.precinct_name, precincts.capacity
FROM voters
INNER JOIN precincts ON voters.precinct_id = precincts.precinct_id;

SELECT first_name, last_name, email, date_of_birth
FROM voters
WHERE voter_id = 1;

SELECT voters.first_name, voters.last_name, elections.election_name
FROM voters
JOIN elections ON voters.precinct_id = elections.precinct_id;

SELECT first_name, last_name, title, email
FROM electionOfficials
WHERE precinct_id = '0';

SELECT first_name || ' ' || last_name AS VolunteerName, role AS Role
FROM volunteers
WHERE precinct_id = '0';

SELECT SUM(voter_count) AS total_voters_turned_out
FROM voter_turnout
WHERE voter_count > 0;
